-- Migracion 21: actualizar saldos (W5) de clientes sin contacto / sin respuesta
-- Fuente: shortlist-carga (10).csv  (593 filas, 593 AF unicos). Los "-" = 0.
-- Actualiza adeudo, semana, semana_siguiente, plazo_remanente SOLO para
-- negociaciones en 'listo_contactar' o 'sin_respuesta'.
-- Orden: PASO 1 (staging) -> PASO 2 (verificacion en seco) -> PASO 3 (update) -> PASO 4 (limpieza).

-- PASO 1: tabla staging con los datos del CSV (idempotente)
drop table if exists public.stg_saldos_w5;

create table public.stg_saldos_w5 (
  af               text primary key,
  adeudo           numeric(12,2) not null,
  semana           numeric(12,2) not null,
  semana_siguiente numeric(12,2) not null,
  plazo_remanente  int not null check (plazo_remanente > 0)
);



-- PASO 2: verificacion EN SECO (no modifica datos). Revisar antes de seguir.

-- 2a. Resumen de coincidencias por AF
select
  (select count(*) from public.stg_saldos_w5) as csv_filas,
  (select count(*) from public.stg_saldos_w5 s
     where exists (select 1 from public.clientes c where c.af = s.af)) as af_con_match,
  (select count(*) from public.stg_saldos_w5 s
     where not exists (select 1 from public.clientes c where c.af = s.af)) as af_sin_match;

-- 2b. AFs del CSV que NO existen en clientes
select s.af
from public.stg_saldos_w5 s
where not exists (select 1 from public.clientes c where c.af = s.af)
order by s.af;

-- 2c. Cuantos clientes se ACTUALIZARIAN (match + status objetivo)
select count(*) as clientes_a_actualizar
from public.clientes c
join public.stg_saldos_w5 s on s.af = c.af
where exists (
  select 1 from public.negociaciones n
  where n.cliente_id = c.id and n.status in ('listo_contactar','sin_respuesta')
);

-- 2d. Desglose por status de los clientes que matchean por AF
select n.status, count(*) as cantidad
from public.clientes c
join public.stg_saldos_w5 s on s.af = c.af
join public.negociaciones n on n.cliente_id = c.id
group by n.status
order by cantidad desc;

-- 2e. Clientes en status objetivo que NO estan en el CSV (quedarian SIN actualizar)
select count(*) as en_status_objetivo_sin_csv
from public.clientes c
join public.negociaciones n on n.cliente_id = c.id
where n.status in ('listo_contactar','sin_respuesta')
  and not exists (select 1 from public.stg_saldos_w5 s where s.af = c.af);


-- PASO 2-bis: 7 clientes estan guardados con el AF invertido (AF#### en vez de ####AF).
-- Confirmado en la verificacion. Agregamos esas 7 variantes al staging con los mismos
-- valores para que el UPDATE del PASO 3 tambien los alcance. Idempotente.
select 'AF' || left(s.af, length(s.af) - 2),
       s.adeudo, s.semana, s.semana_siguiente, s.plazo_remanente
from public.stg_saldos_w5 s
where s.af in ('3422AF','4923AF','6092AF','6143AF','6605AF','7319AF','7779AF')
on conflict (af) do nothing;


-- PASO 3: UPDATE REAL (correr SOLO despues de aprobar el PASO 2)
update public.clientes c
set adeudo           = s.adeudo,
    semana           = s.semana,
    semana_siguiente = s.semana_siguiente,
    plazo_remanente  = s.plazo_remanente,
    updated_at       = now()
from public.stg_saldos_w5 s
where c.af = s.af
  and exists (
    select 1 from public.negociaciones n
    where n.cliente_id = c.id and n.status in ('listo_contactar','sin_respuesta')
  );


